query:
SELECT status, COUNT(*) as cnt FROM articles GROUP BY status ORDER BY cnt DESC;

SELECT 
  COUNT(*) as total,
  SUM(CASE WHEN title = 'Rascunho automático' THEN 1 ELSE 0 END) as rascunhos_automaticos,
  SUM(CASE WHEN title LIKE '%Rascunho%' THEN 1 ELSE 0 END) as todos_rascunhos
FROM articles;

